  const payload = await verifyJWT(token, c.env.JWT_SECRET || 'mandoubak-jwt-secret-2024')
  if (!payload) return c.json({ error: 'التوكن غلط' }, 401)

  let body: unknown
  try { body = await c.req.json() } catch { return c.json({ error: 'بيانات غلط' }, 400) }

  const schema = z.object({
    name: z.string().min(3).max(100),
    address: z.string().min(5).max(500),
    idFrontImageUrl: z.string().min(1),
    idBackImageUrl: z.string().min(1),
  })

  const parsed = schema.safeParse(body)
  if (!parsed.success) return c.json({ error: 'بيانات ناقصة', details: parsed.error.flatten() }, 400)

  const supabase = getSupabaseClient(c.env.SUPABASE_URL, c.env.SUPABASE_SERVICE_ROLE_KEY)

  const { error } = await supabase
    .from('couriers')
    .update({
      name: parsed.data.name,
      address: parsed.data.address,
      id_front_image_url: parsed.data.idFrontImageUrl,
      id_back_image_url: parsed.data.idBackImageUrl,
      status: 'PENDING_REVIEW',
    })
    .eq('user_id', String(payload.userId))

  if (error) return c.json({ error: 'فشل تحديث البيانات' }, 500)

  await supabase
    .from('users')
    .update({ name: parsed.data.name, address: parsed.data.address })
    .eq('id', String(payload.userId))

  return c.json({ success: true, message: 'تم تحديث البيانات وهيتراجع الأدمن' })
})

// =============================================================
// Auth Middleware - Custom JWT (بدون Clerk)
// =============================================================

import { createMiddleware } from 'hono/factory'
import { verifyJWT } from '../lib/jwt-utils'
import type { Env } from '../index'

export type AuthUser = {
  userId: string
  clerkId: string
  role: 'CLIENT' | 'COURIER' | 'ADMIN'
  phone?: string
}

declare module 'hono' {
  interface ContextVariableMap {
    user: AuthUser
  }
}

export const authMiddleware = createMiddleware<{ Bindings: Env }>(async (c, next) => {
  const authHeader = c.req.header('Authorization')

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return c.json({ error: 'مش مسجل دخول' }, 401)
  }

  const token = authHeader.split(' ')[1]

  try {
    const secret = c.env.JWT_SECRET || 'mandoubak-jwt-secret-2024'
    const payload = await verifyJWT(token, secret)

    if (!payload) {
      return c.json({ error: 'التوكن منتهي أو غلط — سجّل دخول تاني' }, 401)
    }

    const userId = String(payload.userId || '')
    const role = String(payload.role || 'CLIENT') as AuthUser['role']
    const phone = String(payload.phone || '')

    if (!userId) {
      return c.json({ error: 'بيانات التوكن غير مكتملة' }, 401)
    }

    c.set('user', {
      userId,
      clerkId: userId,
      role,
      phone,
    })

    await next()
  } catch (err) {
    return c.json({ error: 'خطأ في التحقق من الهوية' }, 401)
  }
})

export const requireRole = (...roles: AuthUser['role'][]) =>
  createMiddleware<{ Bindings: Env }>(async (c, next) => {
    const user = c.get('user')
    if (!roles.includes(user.role)) {
      return c.json({ error: 'مش عندك صلاحية' }, 403)
    }
    await next()
  })

// =============================================================
// Pricing Calculator - حساب سعر التوصيل
// SHOPPING: بناءً على عدد المحلات
// DELIVERY: بناءً على المسافة (Haversine)
// =============================================================

export type Coordinates = {
  lat: number
  lng: number
}

export type PricingZone = {
  zone: string
  price_per_km: number
  minimum_fee: number
  maximum_fee?: number | null
  price_per_shop?: number | null
  base_fee_shopping?: number | null
}

export type DeliveryPriceResult = {
  distanceKm: number
  zone: string
  finalFee: number
  breakdown: string
}

export type ShoppingPriceResult = {
  numShops: number
  zone: string
  finalFee: number
  breakdown: string
}

export function calculateDistance(from: Coordinates, to: Coordinates): number {
  const R = 6371
  const dLat = toRadians(to.lat - from.lat)
  const dLng = toRadians(to.lng - from.lng)
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRadians(from.lat)) * Math.cos(toRadians(to.lat)) *
    Math.sin(dLng / 2) * Math.sin(dLng / 2)
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
  return Math.round(R * c * 100) / 100
}

function toRadians(degrees: number): number {
  return degrees * (Math.PI / 180)
}

// حساب سعر أوردر التوصيل (بالمسافة)
export function calculateDeliveryFee(
  distanceKm: number,
  pricingZone: PricingZone
): DeliveryPriceResult {
  const calculatedFee = distanceKm * pricingZone.price_per_km
  let finalFee = Math.max(calculatedFee, pricingZone.minimum_fee)
  if (pricingZone.maximum_fee) finalFee = Math.min(finalFee, pricingZone.maximum_fee)
  finalFee = Math.ceil(finalFee)

  return {
    distanceKm,
    zone: pricingZone.zone,
    finalFee,
    breakdown: `${distanceKm} كم × ${pricingZone.price_per_km} جنيه = ${Math.round(calculatedFee)} جنيه (أدنى: ${pricingZone.minimum_fee} جنيه)`,
  }
}

// حساب سعر أوردر المشتريات (بعدد المحلات)
export function calculateShoppingFee(
  numShops: number,
  pricingZone: PricingZone
): ShoppingPriceResult {
  const baseFee = pricingZone.base_fee_shopping ?? pricingZone.minimum_fee
  const perShop = pricingZone.price_per_shop ?? 5
  const shops = Math.max(1, Math.min(numShops, 4))  // 1 to 4

  const calculatedFee = baseFee + (shops - 1) * perShop
  const finalFee = Math.ceil(calculatedFee)

  return {
    numShops: shops,
    zone: pricingZone.zone,
    finalFee,
    breakdown: `${baseFee} جنيه أساسي + ${shops - 1} محل إضافي × ${perShop} جنيه = ${finalFee} جنيه`,
  }
}

export function detectZone(coords: Coordinates): string {
  if (coords.lat >= 29.9 && coords.lat <= 30.1 &&
      coords.lng >= 30.8 && coords.lng <= 31.1) {
    return 'الجيزة'
  }
  if (coords.lat >= 29.7 && coords.lat <= 30.3 &&
      coords.lng >= 31.0 && coords.lng <= 31.6) {
    return 'القاهرة'
  }
  return 'default'
}

