// =============================================================
// Admin Couriers - إدارة المناديب (بيانات حقيقية)
// =============================================================

import { useState, useEffect } from 'react'
import toast from 'react-hot-toast'
import { Truck, CheckCircle, XCircle, Clock, Star, Phone, MapPin, Loader2, RefreshCw } from 'lucide-react'
import { useAuth } from '../../lib/auth-context'

interface Courier {
  id: string
  name: string
  phone: string
  address: string
  status: string
  rating: number
  total_deliveries: number
  is_online: boolean
  id_front_image_url: string
  id_back_image_url: string
  created_at: string
}

const STATUS_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
  PENDING_REVIEW: { label: 'قيد المراجعة', color: 'text-yellow-700', bg: 'bg-yellow-100' },
  APPROVED: { label: 'معتمد', color: 'text-green-700', bg: 'bg-green-100' },
  REJECTED: { label: 'مرفوض', color: 'text-red-700', bg: 'bg-red-100' },
  SUSPENDED: { label: 'موقوف', color: 'text-gray-700', bg: 'bg-gray-100' },
}

export default function AdminCouriers() {
  const { token } = useAuth()
  const [couriers, setCouriers] = useState<Courier[]>([])
  const [loading, setLoading] = useState(true)
  const [filter, setFilter] = useState<string>('all')
  const [updating, setUpdating] = useState<string | null>(null)

  useEffect(() => { loadCouriers() }, [])

  async function loadCouriers() {
    if (!token) return
    setLoading(true)
    try {
      const res = await fetch('/api/admin/couriers', {
        headers: { Authorization: `Bearer ${token}` },
      })
      if (res.ok) {
        const data = await res.json()
        setCouriers(data.couriers || [])
      } else {
        toast.error('مقدرناش نجيب المناديب')
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    } finally {
      setLoading(false)
    }
  }

  async function updateStatus(courierId: string, status: string) {
    if (!token) return
    setUpdating(courierId)
    try {
      const res = await fetch(`/api/admin/couriers/${courierId}/approve`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ status }),
      })
      if (res.ok) {
        toast.success(status === 'APPROVED' ? '✅ تم الموافقة على المندوب' :
          status === 'REJECTED' ? '❌ تم رفض المندوب' : '⛔ تم إيقاف المندوب')
        setCouriers(couriers.map(c => c.id === courierId ? { ...c, status } : c))
      } else {
        toast.error('فشل التحديث')
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    } finally {
      setUpdating(null)
    }
  }

  const filtered = filter === 'all' ? couriers : couriers.filter(c => c.status === filter)
  const pendingCount = couriers.filter(c => c.status === 'PENDING_REVIEW').length

  return (
    <div className="max-w-2xl mx-auto space-y-5">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Truck className="text-orange-500" size={28} />
          <div>
            <h1 className="text-2xl font-black">إدارة المناديب</h1>
            {pendingCount > 0 && (
              <p className="text-yellow-600 text-sm font-semibold">{pendingCount} مندوب ينتظر الموافقة ⏳</p>
            )}
          </div>
        </div>
        <button onClick={loadCouriers} className="p-2 hover:bg-gray-100 rounded-xl transition-colors" title="تحديث">
          <RefreshCw size={20} className={`text-gray-500 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      {/* Filter Tabs */}
      <div className="flex gap-1 bg-gray-100 p-1 rounded-xl overflow-x-auto">
        {[
          { key: 'all', label: `الكل (${couriers.length})` },
          { key: 'PENDING_REVIEW', label: `ينتظر (${couriers.filter(c => c.status === 'PENDING_REVIEW').length})` },
          { key: 'APPROVED', label: `معتمد (${couriers.filter(c => c.status === 'APPROVED').length})` },
          { key: 'REJECTED', label: `مرفوض (${couriers.filter(c => c.status === 'REJECTED').length})` },
          { key: 'SUSPENDED', label: `موقوف (${couriers.filter(c => c.status === 'SUSPENDED').length})` },
        ].map(tab => (
          <button key={tab.key} onClick={() => setFilter(tab.key)}
            className={`flex-shrink-0 px-3 py-2 rounded-lg font-bold text-xs transition-all ${
              filter === tab.key ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-600'
            }`}>
            {tab.label}
          </button>
        ))}
      </div>

      {/* Couriers List */}
      {loading ? (
        Array.from({ length: 3 }).map((_, i) => (
          <div key={i} className="card animate-pulse h-32 bg-gray-100" />
        ))
      ) : filtered.length === 0 ? (
        <div className="text-center py-12 text-gray-400">
          <Truck size={48} className="mx-auto mb-3 opacity-30" />
          <p>مفيش مناديب في هذه الفئة</p>
          {couriers.length === 0 && (
            <p className="text-sm mt-2">لو فيه خطأ في الاتصال، تأكد من الـ backend</p>
          )}
        </div>
      ) : (
        filtered.map(courier => {
          const sc = STATUS_CONFIG[courier.status] || STATUS_CONFIG.PENDING_REVIEW
          const isUpdating = updating === courier.id
          return (
            <div key={courier.id} className="card">
              <div className="flex items-start justify-between">
                <div className="flex items-center gap-3">
                  <div className="relative">
                    <div className="w-12 h-12 bg-orange-100 rounded-xl flex items-center justify-center flex-shrink-0">
                      <span className="text-orange-600 font-black text-lg">{courier.name[0]}</span>
                    </div>
                    {courier.is_online && (
                      <span className="absolute -bottom-1 -right-1 w-3.5 h-3.5 bg-green-500 border-2 border-white rounded-full" />
                    )}
                  </div>
                  <div>
                    <h3 className="font-bold">{courier.name}</h3>
                    <div className="flex items-center gap-1 text-sm text-gray-500">
                      <Phone size={12} />
                      <span dir="ltr">{courier.phone}</span>
                    </div>
                    {courier.address && (
                      <div className="flex items-center gap-1 text-xs text-gray-400 mt-0.5">
                        <MapPin size={11} />
                        <span>{courier.address.slice(0, 40)}{courier.address.length > 40 ? '...' : ''}</span>
                      </div>
                    )}
                  </div>
                </div>
                <span className={`text-xs font-bold px-2 py-1 rounded-full ${sc.bg} ${sc.color}`}>
                  {sc.label}
                </span>
              </div>

              <div className="mt-3 flex items-center gap-4 text-xs text-gray-500">
                <div className="flex items-center gap-1">
                  <Star size={12} className="text-yellow-400" />
                  {courier.rating.toFixed(1)}
                </div>
                <div className="flex items-center gap-1">
                  <Truck size={12} />
                  {courier.total_deliveries} توصيلة
                </div>
                <div className="flex items-center gap-1">
                  <Clock size={12} />
                  {new Date(courier.created_at).toLocaleDateString('ar-EG')}
                </div>
                {courier.is_online && (
                  <span className="text-green-600 font-semibold">● متصل الآن</span>
                )}
              </div>

              {/* ID Images Status */}
              {courier.status === 'PENDING_REVIEW' && (
                <div className="mt-4 space-y-3">
                  <div className="grid grid-cols-2 gap-2">
                    <div className={`rounded-xl p-2 text-center text-xs ${courier.id_front_image_url ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                      🪪 وجه البطاقة
                      <div className="mt-1 font-bold">
                        {courier.id_front_image_url ? '✅ مرفوع' : '❌ غير مرفوع'}
                      </div>
                    </div>
                    <div className={`rounded-xl p-2 text-center text-xs ${courier.id_back_image_url ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                      🪪 ضهر البطاقة
                      <div className="mt-1 font-bold">
                        {courier.id_back_image_url ? '✅ مرفوع' : '❌ غير مرفوع'}
                      </div>
                    </div>
                  </div>

                  {!courier.id_front_image_url || !courier.id_back_image_url ? (
                    <div className="bg-red-50 border border-red-200 rounded-xl p-3 text-sm text-red-700 text-center">
                      ⚠️ صور البطاقة ناقصة — ارفضه وخليه يكمل التسجيل
                    </div>
                  ) : null}

                  <div className="flex gap-2">
                    <button disabled={isUpdating} onClick={() => updateStatus(courier.id, 'APPROVED')}
                      className="flex-1 bg-green-500 hover:bg-green-600 disabled:opacity-50 text-white font-bold py-2.5 rounded-xl text-sm flex items-center justify-center gap-1 transition-all">
                      {isUpdating ? <Loader2 size={16} className="animate-spin" /> : <CheckCircle size={16} />}
                      موافقة
                    </button>
                    <button disabled={isUpdating} onClick={() => updateStatus(courier.id, 'REJECTED')}
                      className="flex-1 bg-red-500 hover:bg-red-600 disabled:opacity-50 text-white font-bold py-2.5 rounded-xl text-sm flex items-center justify-center gap-1 transition-all">
                      {isUpdating ? <Loader2 size={16} className="animate-spin" /> : <XCircle size={16} />}
                      رفض
                    </button>
                  </div>
                </div>
              )}

              {courier.status === 'APPROVED' && (
                <button disabled={isUpdating} onClick={() => updateStatus(courier.id, 'SUSPENDED')}
                  className="mt-3 w-full bg-gray-100 hover:bg-red-50 text-gray-600 hover:text-red-600 font-bold py-2 rounded-xl text-sm transition-all flex items-center justify-center gap-2">
                  {isUpdating ? <Loader2 size={16} className="animate-spin" /> : null}
                  إيقاف المندوب
                </button>
              )}

              {courier.status === 'SUSPENDED' && (
                <button disabled={isUpdating} onClick={() => updateStatus(courier.id, 'APPROVED')}
                  className="mt-3 w-full bg-green-100 hover:bg-green-200 text-green-700 font-bold py-2 rounded-xl text-sm transition-all flex items-center justify-center gap-2">
                  {isUpdating ? <Loader2 size={16} className="animate-spin" /> : null}
                  إعادة التفعيل
                </button>
              )}

              {courier.status === 'REJECTED' && (
                <button disabled={isUpdating} onClick={() => updateStatus(courier.id, 'PENDING_REVIEW')}
                  className="mt-3 w-full bg-yellow-100 hover:bg-yellow-200 text-yellow-700 font-bold py-2 rounded-xl text-sm transition-all">
                  إعادة للمراجعة
                </button>
              )}
            </div>
          )
        })
      )}
    </div>
  )
}

// =============================================================
// Admin Clients - قائمة العملاء الحقيقية
// =============================================================

import { useState, useEffect } from 'react'
import toast from 'react-hot-toast'
import { Users, Phone, MapPin, Clock, Search, RefreshCw } from 'lucide-react'
import { useAuth } from '../../lib/auth-context'

interface Client {
  id: string
  name: string
  phone: string
  address: string
  last_seen_at: string
  created_at: string
  isActiveNow: boolean
}

export default function AdminClients() {
  const { token } = useAuth()
  const [clients, setClients] = useState<Client[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')

  useEffect(() => { loadClients() }, [])

  async function loadClients() {
    if (!token) return
    setLoading(true)
    try {
      const res = await fetch('/api/admin/clients', {
        headers: { Authorization: `Bearer ${token}` },
      })
      if (res.ok) {
        const data = await res.json()
        setClients(data.clients || [])
      } else {
        toast.error('مقدرناش نجيب العملاء')
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    } finally {
      setLoading(false)
    }
  }

  const filtered = clients.filter(c =>
    !search || c.name?.includes(search) || c.phone?.includes(search) || c.address?.includes(search)
  )

  const activeNow = clients.filter(c => c.isActiveNow).length

  return (
    <div className="max-w-2xl mx-auto space-y-5">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Users className="text-green-500" size={28} />
          <div>
            <h1 className="text-2xl font-black">العملاء</h1>
            <p className="text-gray-500 text-sm">
              {clients.length} عميل | {activeNow} نشط دلوقتي
            </p>
          </div>
        </div>
        <button onClick={loadClients} className="p-2 hover:bg-gray-100 rounded-xl transition-colors">
          <RefreshCw size={20} className={`text-gray-500 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 gap-4">
        <div className="card text-center">
          <div className="text-2xl font-black text-green-600">{clients.length}</div>
          <div className="text-sm text-gray-500">إجمالي العملاء</div>
        </div>
        <div className="card text-center">
          <div className="text-2xl font-black text-blue-600">{activeNow}</div>
          <div className="text-sm text-gray-500">نشط الآن</div>
          <div className="text-xs text-blue-400">(آخر 15 دقيقة)</div>
        </div>
      </div>

      {/* Search */}
      <div className="relative">
        <Search size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" />
        <input
          type="text"
          value={search}
          onChange={e => setSearch(e.target.value)}
          placeholder="ابحث بالاسم أو التليفون..."
          className="input pr-10 w-full"
        />
      </div>

      {/* Clients List */}
      {loading ? (
        Array.from({ length: 5 }).map((_, i) => (
          <div key={i} className="card animate-pulse h-20 bg-gray-100" />
        ))
      ) : filtered.length === 0 ? (
        <div className="text-center py-12 text-gray-400">
          <Users size={48} className="mx-auto mb-3 opacity-30" />
          <p>{search ? 'مفيش نتائج للبحث ده' : 'مفيش عملاء مسجلين لحد دلوقتي'}</p>
        </div>
      ) : (
        <div className="space-y-3">
          {filtered.map(client => (
            <div key={client.id} className={`card flex items-start justify-between ${
              client.isActiveNow ? 'border-l-4 border-l-green-400' : ''
            }`}>
              <div className="flex items-start gap-3">
                <div className="relative">
                  <div className="w-11 h-11 bg-blue-100 rounded-xl flex items-center justify-center">
                    <span className="text-blue-600 font-black">{(client.name || client.phone)[0]}</span>
                  </div>
                  {client.isActiveNow && (
                    <span className="absolute -bottom-1 -right-1 w-3 h-3 bg-green-500 border-2 border-white rounded-full" />
                  )}
                </div>
                <div>
                  <h3 className="font-bold text-sm">{client.name || 'عميل'}</h3>
                  <div className="flex items-center gap-1 text-xs text-gray-500">
                    <Phone size={11} />
                    <span dir="ltr">{client.phone}</span>
                  </div>
                  {client.address && (
                    <div className="flex items-center gap-1 text-xs text-gray-400 mt-0.5 max-w-[200px]">
                      <MapPin size={11} className="flex-shrink-0" />
                      <span className="truncate">{client.address}</span>
                    </div>
                  )}
                </div>
              </div>
              <div className="text-right">
                {client.isActiveNow ? (
                  <span className="text-xs font-bold text-green-600 bg-green-50 px-2 py-1 rounded-full">● نشط الآن</span>
                ) : (
                  <div className="flex items-center gap-1 text-xs text-gray-400">
                    <Clock size={11} />
                    {client.last_seen_at
                      ? new Date(client.last_seen_at).toLocaleDateString('ar-EG')
                      : 'لم يدخل بعد'}
                  </div>
                )}
                <div className="text-xs text-gray-400 mt-1">
                  سجّل: {new Date(client.created_at).toLocaleDateString('ar-EG')}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

// =============================================================
// Admin Orders - كل الأوردرات الحقيقية
// =============================================================

import { useState, useEffect } from 'react'
import toast from 'react-hot-toast'
import { Package, ShoppingBag, Truck, RefreshCw, ChevronLeft, ChevronRight } from 'lucide-react'
import { useAuth } from '../../lib/auth-context'

interface Order {
  id: string
  order_number: string
  type: 'SHOPPING' | 'DELIVERY'
  status: string
  delivery_fee: number
  distance_km: number
  num_shops: number
  pickup_details: string
  delivery_details: string
  recipient_phone: string
  notes: string
  created_at: string
  order_items?: { name: string; quantity: number; price?: number; shop_name?: string }[]
  couriers?: { name: string; phone: string }
  users?: { name: string; phone: string }
}

interface Pagination {
  page: number
  limit: number
  total: number
  pages: number
}

const STATUS_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
  PENDING:    { label: 'ينتظر مندوب', color: 'text-yellow-700', bg: 'bg-yellow-100' },
  ACCEPTED:   { label: 'تم القبول',   color: 'text-blue-700',   bg: 'bg-blue-100'   },
  PICKED_UP:  { label: 'مع المندوب',  color: 'text-purple-700', bg: 'bg-purple-100' },
  DELIVERED:  { label: 'تم التوصيل', color: 'text-green-700',  bg: 'bg-green-100'  },
  CANCELLED:  { label: 'ملغي',        color: 'text-red-700',    bg: 'bg-red-100'    },
}

export default function AdminOrders() {
  const { token } = useAuth()
  const [orders, setOrders] = useState<Order[]>([])
  const [pagination, setPagination] = useState<Pagination>({ page: 1, limit: 20, total: 0, pages: 1 })
  const [loading, setLoading] = useState(true)
  const [filter, setFilter] = useState('all')
  const [page, setPage] = useState(1)
  const [expanded, setExpanded] = useState<string | null>(null)

  useEffect(() => { loadOrders() }, [filter, page])

  async function loadOrders() {
    if (!token) return
    setLoading(true)
    try {
      const params = new URLSearchParams()
      if (filter !== 'all') params.set('status', filter)
      params.set('page', String(page))

      const res = await fetch(`/api/admin/orders?${params}`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      if (res.ok) {
        const data = await res.json()
        setOrders(data.orders || [])
        setPagination(data.pagination || { page: 1, limit: 20, total: 0, pages: 1 })
      } else {
        toast.error('مقدرناش نجيب الأوردرات')
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    } finally {
      setLoading(false)
    }
  }

  const filterTabs = [
    { key: 'all', label: 'الكل' },
    { key: 'PENDING', label: 'ينتظر' },
    { key: 'ACCEPTED', label: 'قُبل' },
    { key: 'PICKED_UP', label: 'مع مندوب' },
    { key: 'DELIVERED', label: 'تم' },
    { key: 'CANCELLED', label: 'ملغي' },
  ]

  return (
    <div className="max-w-2xl mx-auto space-y-5">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Package className="text-orange-500" size={28} />
          <div>
            <h1 className="text-2xl font-black">الأوردرات</h1>
            <p className="text-gray-500 text-sm">{pagination.total} أوردر إجمالي</p>
          </div>
        </div>
        <button onClick={loadOrders} className="p-2 hover:bg-gray-100 rounded-xl transition-colors">
          <RefreshCw size={20} className={`text-gray-500 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      {/* Filter Tabs */}
      <div className="flex gap-1 bg-gray-100 p-1 rounded-xl overflow-x-auto">
        {filterTabs.map(tab => (
          <button key={tab.key} onClick={() => { setFilter(tab.key); setPage(1) }}
            className={`flex-shrink-0 px-3 py-2 rounded-lg font-bold text-xs transition-all ${
              filter === tab.key ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-600'
            }`}>
            {tab.label}
          </button>
        ))}
      </div>

      {/* Orders List */}
      {loading ? (
        Array.from({ length: 5 }).map((_, i) => (
          <div key={i} className="card animate-pulse h-24 bg-gray-100" />
        ))
      ) : orders.length === 0 ? (
        <div className="text-center py-12 text-gray-400">
          <Package size={48} className="mx-auto mb-3 opacity-30" />
          <p>مفيش أوردرات في هذه الفئة</p>
        </div>
      ) : (
        orders.map(order => {
          const sc = STATUS_CONFIG[order.status] || STATUS_CONFIG.PENDING
          const isExp = expanded === order.id
          return (
            <div key={order.id} className="card">
              <div className="flex items-start justify-between gap-2">
                <div className="flex items-center gap-2">
                  <div className={`w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0 ${
                    order.type === 'SHOPPING' ? 'bg-orange-100' : 'bg-blue-100'
                  }`}>
                    {order.type === 'SHOPPING'
                      ? <ShoppingBag size={18} className="text-orange-500" />
                      : <Truck size={18} className="text-blue-500" />
                    }
                  </div>
                  <div>
                    <h3 className="font-bold text-sm">{order.order_number}</h3>
                    <div className="text-xs text-gray-400">
                      {new Date(order.created_at).toLocaleString('ar-EG')}
                    </div>
                  </div>
                </div>
                <div className="text-right flex flex-col items-end gap-1">
                  <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${sc.bg} ${sc.color}`}>
                    {sc.label}
                  </span>
                  <span className="text-sm font-black text-orange-600">{order.delivery_fee} جنيه</span>
                </div>
              </div>

              <div className="mt-2 grid grid-cols-2 gap-2 text-xs text-gray-500">
                {order.users && (
                  <div>👤 العميل: <span className="font-semibold text-gray-700">{order.users.name || order.users.phone}</span></div>
                )}
                {order.couriers && (
                  <div>🛵 المندوب: <span className="font-semibold text-gray-700">{order.couriers.name}</span></div>
                )}
                {order.type === 'SHOPPING' && order.num_shops > 0 && (
                  <div>🏪 محلات: <span className="font-semibold">{order.num_shops}</span></div>
                )}
                {order.type === 'DELIVERY' && order.distance_km > 0 && (
                  <div>📍 مسافة: <span className="font-semibold">{order.distance_km} كم</span></div>
                )}
              </div>

              <button onClick={() => setExpanded(isExp ? null : order.id)}
                className="mt-2 text-xs text-orange-600 font-semibold hover:underline">
                {isExp ? '▲ إخفاء التفاصيل' : '▼ عرض التفاصيل'}
              </button>

              {isExp && (
                <div className="mt-3 space-y-2 text-sm border-t pt-3">
                  <div className="text-gray-600">
                    <span className="font-bold">الاستلام:</span> {order.pickup_details}
                  </div>
                  <div className="text-gray-600">
                    <span className="font-bold">التسليم:</span> {order.delivery_details}
                  </div>
                  {order.recipient_phone && (
                    <div className="text-gray-600">
                      <span className="font-bold">تليفون المستلم:</span> {order.recipient_phone}
                    </div>
                  )}
                  {order.notes && (
                    <div className="text-gray-600">
                      <span className="font-bold">ملاحظات:</span> {order.notes}
                    </div>
                  )}
                  {order.order_items && order.order_items.length > 0 && (
                    <div>
                      <div className="font-bold mb-1">المنتجات:</div>
                      {order.order_items.slice(0, 10).map((item, i) => (
                        <div key={i} className="flex items-center gap-2 text-xs text-gray-500 mb-0.5">
                          <span>•</span>
                          {item.shop_name && <span className="font-semibold text-orange-600">[{item.shop_name}]</span>}
                          <span>{item.name} × {item.quantity}</span>
                          {item.price && <span className="text-green-600">({item.price} جنيه)</span>}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </div>
          )
        })
      )}

      {/* Pagination */}
      {pagination.pages > 1 && (
        <div className="flex items-center justify-center gap-3">
          <button disabled={page <= 1} onClick={() => setPage(p => p - 1)}
            className="p-2 hover:bg-gray-100 disabled:opacity-30 rounded-xl transition-colors">
            <ChevronRight size={20} />
          </button>
          <span className="font-bold text-sm">
            صفحة {page} من {pagination.pages} ({pagination.total} أوردر)
          </span>
          <button disabled={page >= pagination.pages} onClick={() => setPage(p => p + 1)}
            className="p-2 hover:bg-gray-100 disabled:opacity-30 rounded-xl transition-colors">
            <ChevronLeft size={20} />
          </button>
        </div>
      )}
    </div>
  )
}

