import { useState, useRef } from 'react'
import { useNavigate } from 'react-router-dom'
import toast from 'react-hot-toast'
import {
  CreditCard, Upload, CheckCircle, ArrowLeft,
  Clock, ShieldCheck, Loader2
} from 'lucide-react'
import { useAuth } from '../../lib/auth-context'

type Step = 'id-upload' | 'review' | 'done'

export default function CourierRegister() {
  const navigate = useNavigate()
  const { user, token } = useAuth()
  const [step, setStep] = useState<Step>('id-upload')
  const [submitting, setSubmitting] = useState(false)
  const [frontFile, setFrontFile] = useState<File | null>(null)
  const [backFile, setBackFile] = useState<File | null>(null)
  const [frontPreview, setFrontPreview] = useState<string | null>(null)
  const [backPreview, setBackPreview] = useState<string | null>(null)
  const frontRef = useRef<HTMLInputElement>(null)
  const backRef = useRef<HTMLInputElement>(null)

  // لو مش مندوب → روح صفحة رئيسية
  if (!user || user.role !== 'courier') {
    navigate('/')
    return null
  }

  // لو عنده بطاقة مرفوعة → اعرض حالة الانتظار
  if (user.courierStatus === 'APPROVED') {
    return (
      <div className="max-w-md mx-auto text-center py-16 space-y-4">
        <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto">
          <CheckCircle className="text-green-500" size={40} />
        </div>
        <h2 className="text-xl font-black">حسابك معتمد! ✅</h2>
        <p className="text-gray-500">يمكنك استلام الطلبات دلوقتي</p>
        <button onClick={() => navigate('/courier/dashboard')} className="btn-primary">
          اذهب للوحة التحكم
        </button>
      </div>
    )
  }

  function handleFileChange(
    file: File | null,
    setFile: (f: File | null) => void,
    setPreview: (s: string | null) => void
  ) {
    if (!file) return
    if (file.size > 5 * 1024 * 1024) { toast.error('حجم الصورة أكبر من 5MB'); return }
    if (!['image/jpeg', 'image/png', 'image/webp'].includes(file.type)) {
      toast.error('نوع الملف غير مدعوم (JPG, PNG, WEBP فقط)')
      return
    }
    setFile(file)
    const reader = new FileReader()
    reader.onload = e => setPreview(e.target?.result as string)
    reader.readAsDataURL(file)
  }

  async function uploadImages() {
    if (!frontFile || !backFile) {
      toast.error('ارفع صورة وجه وضهر البطاقة')
      return
    }
    if (!token) {
      toast.error('سجّل دخول الأول')
      navigate('/login')
      return
    }

    setSubmitting(true)
    try {
      const formData = new FormData()
      formData.append('idFront', frontFile)
      formData.append('idBack', backFile)
      formData.append('courierId', user.courierId || user.id)

      const res = await fetch('/api/upload', {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
        body: formData,
      })

      if (res.ok) {
        toast.success('✅ تم رفع الصور بنجاح!')
        setStep('review')
      } else {
        const data = await res.json().catch(() => ({}))
        // Even if upload fails (e.g., R2 not configured), show review step
        if (res.status === 501 || res.status === 400) {
          toast('⚠️ رفع الصور مش متاح دلوقتي — سيتم مراجعة طلبك يدوياً', { icon: 'ℹ️' })
          setStep('review')
        } else {
          toast.error(data.error || 'فشل رفع الصور، جرب تاني')
        }
      }
    } catch {
      // Network error — proceed anyway, show review step
      toast('⚠️ مشكلة في الاتصال — سيتم مراجعة طلبك يدوياً', { icon: 'ℹ️' })
      setStep('review')
    } finally {
      setSubmitting(false)
    }
  }

  return (
    <div className="max-w-lg mx-auto space-y-6">
      <div>
        <h1 className="text-2xl font-black">أكمّل تسجيلك كمندوب 🛵</h1>
        <p className="text-gray-500 text-sm mt-1">ارفع صور البطاقة الشخصية عشان الأدمن يراجع حسابك</p>
      </div>

      {/* Progress */}
      <div className="flex items-center gap-2">
        {[
          { key: 'id-upload', label: 'رفع البطاقة', num: 1 },
          { key: 'review', label: 'تحت المراجعة', num: 2 },
          { key: 'done', label: 'مقبول', num: 3 },
        ].map((s, i) => {
          const steps = ['id-upload', 'review', 'done']
          const currentIdx = steps.indexOf(step)
          const thisIdx = i
          return (
            <div key={s.key} className="flex items-center gap-2 flex-1">
              <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold transition-all ${
                currentIdx === thisIdx ? 'bg-orange-500 text-white' :
                currentIdx > thisIdx ? 'bg-green-500 text-white' :
                'bg-gray-200 text-gray-500'
              }`}>
                {currentIdx > thisIdx ? '✓' : s.num}
              </div>
              <span className="text-xs text-gray-500 hidden sm:block">{s.label}</span>
              {i < 2 && (
                <div className={`flex-1 h-1 rounded-full ${currentIdx > thisIdx ? 'bg-green-400' : 'bg-gray-200'}`} />
              )}
            </div>
          )
        })}
      </div>

      {/* User Info Banner */}
      <div className="bg-orange-50 border border-orange-200 rounded-2xl p-4">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-orange-500 rounded-xl flex items-center justify-center text-white font-black">
            {user.name?.[0] || '?'}
          </div>
          <div>
            <div className="font-bold">{user.name}</div>
            <div className="text-sm text-gray-500" dir="ltr">{user.phone}</div>
          </div>
        </div>
      </div>

      {/* Step 1: Upload ID */}
      {step === 'id-upload' && (
        <div className="space-y-4 animate-fade-in">
          <div className="card space-y-4">
            <h2 className="font-bold text-lg flex items-center gap-2">
              <CreditCard className="text-orange-500" size={20} />
              صور البطاقة الشخصية
            </h2>

            {[
              { label: 'وجه البطاقة (الصورة والاسم) *', ref: frontRef, file: frontFile, preview: frontPreview, setFile: setFrontFile, setPreview: setFrontPreview },
              { label: 'ضهر البطاقة *', ref: backRef, file: backFile, preview: backPreview, setFile: setBackFile, setPreview: setBackPreview },
            ].map((img, i) => (
              <div key={i}>
                <label className="block text-sm font-bold text-gray-600 mb-2">{img.label}</label>
                <div
                  onClick={() => img.ref.current?.click()}
                  className={`border-2 border-dashed rounded-2xl p-6 text-center cursor-pointer transition-all ${
                    img.preview ? 'border-green-400 bg-green-50' : 'border-gray-300 hover:border-orange-400 hover:bg-orange-50'
                  }`}
                >
                  <input
                    ref={img.ref}
                    type="file"
                    accept="image/*"
                    className="hidden"
                    onChange={e => handleFileChange(e.target.files?.[0] || null, img.setFile, img.setPreview)}
                  />
                  {img.preview ? (
                    <div>
                      <img src={img.preview} alt={img.label} className="h-32 mx-auto rounded-xl object-cover mb-2" />
                      <p className="text-green-600 font-bold text-sm">✅ تم اختيار الصورة</p>
                      <p className="text-xs text-gray-400 mt-1">انقر للتغيير</p>
                    </div>
                  ) : (
                    <div>
                      <Upload className="mx-auto mb-3 text-gray-400" size={32} />
                      <p className="font-bold text-gray-700">{img.label}</p>
                      <p className="text-xs text-gray-400 mt-1">JPG, PNG حتى 5MB</p>
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>

          <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 text-sm text-blue-700">
            <ShieldCheck size={16} className="inline ml-1" />
            <strong>أمان:</strong> صورك محمية ومش بتتشار مع أي جهة خارجية
          </div>

          <button
            disabled={submitting || !frontFile || !backFile}
            onClick={uploadImages}
            className="btn-primary w-full flex items-center justify-center gap-2 text-lg"
          >
            {submitting ? (
              <><Loader2 size={20} className="animate-spin" />جاري الرفع...</>
            ) : (
              <><Upload size={20} />رفع الصور والمتابعة</>
            )}
          </button>

          <button
            onClick={() => setStep('review')}
            className="w-full text-gray-400 text-sm hover:text-gray-600 transition-colors"
          >
            تخطّي الآن (ارفع لاحقاً)
          </button>
        </div>
      )}

      {/* Step 2: Under Review */}
      {step === 'review' && (
        <div className="space-y-4 animate-fade-in text-center">
          <div className="flex items-center gap-3 justify-start">
            <button onClick={() => setStep('id-upload')} className="p-2 hover:bg-gray-100 rounded-xl">
              <ArrowLeft size={20} />
            </button>
            <h2 className="font-bold text-lg">تحت المراجعة ⏳</h2>
          </div>

          <div className="card py-10">
            <div className="w-20 h-20 bg-yellow-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <Clock className="text-yellow-500" size={40} />
            </div>
            <h3 className="text-xl font-black mb-2">طلبك وصلنا! 🎉</h3>
            <p className="text-gray-500">بياناتك تحت المراجعة من فريقنا</p>
            <p className="text-gray-400 text-sm mt-2">خلال 24 ساعة هيبلغوك بالنتيجة</p>
          </div>

          <div className="card text-right space-y-3">
            <h4 className="font-bold">✅ إيه اللي اتعمل؟</h4>
            <div className="space-y-2 text-sm text-gray-600">
              <div className="flex items-center gap-2">
                <span className="text-green-500">✓</span>
                تم إنشاء حسابك بنجاح
              </div>
              <div className="flex items-center gap-2">
                <span className={frontFile ? 'text-green-500' : 'text-gray-300'}>
                  {frontFile ? '✓' : '○'}
                </span>
                {frontFile ? 'تم رفع وجه البطاقة' : 'لم يتم رفع وجه البطاقة بعد'}
              </div>
              <div className="flex items-center gap-2">
                <span className={backFile ? 'text-green-500' : 'text-gray-300'}>
                  {backFile ? '✓' : '○'}
                </span>
                {backFile ? 'تم رفع ضهر البطاقة' : 'لم يتم رفع ضهر البطاقة بعد'}
              </div>
              <div className="flex items-center gap-2">
                <span className="text-yellow-500">⏳</span>
                في انتظار موافقة الأدمن
              </div>
            </div>
          </div>

          <button
            onClick={() => navigate('/courier/dashboard')}
            className="btn-primary w-full flex items-center justify-center gap-2"
          >
            <CheckCircle size={20} />
            اذهب للوحة التحكم
          </button>
        </div>
      )}
    </div>
  )
}

// =============================================================
// Courier Dashboard - بيانات حقيقية من API (بدون Demo)
// =============================================================

import { useState, useEffect, useCallback } from 'react'
import toast from 'react-hot-toast'
import {
  Truck, Package, Clock, MapPin, CheckCircle,
  Wifi, WifiOff, RefreshCw, ShoppingBag, Phone, AlertTriangle
} from 'lucide-react'
import { useAuth } from '../../lib/auth-context'
import { useNavigate } from 'react-router-dom'

interface OrderItem {
  name: string
  quantity: number
  shop_name?: string
}

interface Order {
  id: string
  order_number: string
  type: 'SHOPPING' | 'DELIVERY'
  status: string
  pickup_details?: string
  delivery_details?: string
  recipient_phone?: string
  distance_km?: number
  num_shops?: number
  delivery_fee: number
  created_at: string
  notes?: string
  order_items?: OrderItem[]
}

const API = '/api'
const REFRESH_INTERVAL_MS = 15000

export default function CourierDashboard() {
  const { user, token } = useAuth()
  const navigate = useNavigate()
  const [pendingOrders, setPendingOrders] = useState<Order[]>([])
  const [myOrders, setMyOrders] = useState<Order[]>([])
  const [accepting, setAccepting] = useState<string | null>(null)
  const [updatingStatus, setUpdatingStatus] = useState<string | null>(null)
  const [isOnline, setIsOnline] = useState(true)
  const [tab, setTab] = useState<'pending' | 'mine'>('pending')
  const [loading, setLoading] = useState(true)
  const [lastRefresh, setLastRefresh] = useState(new Date())
  const [courierStatus, setCourierStatus] = useState<string | null>(null)
  const [courierStatusError, setCourierStatusError] = useState<string | null>(null)

  // لو مش مندوب
  if (!user || user.role !== 'courier') {
    navigate('/')
    return null
  }

  const fetchPendingOrders = useCallback(async () => {
    if (!token || !isOnline) return
    try {
      const res = await fetch(`${API}/orders/pending`, {
        headers: { Authorization: `Bearer ${token}` },
      })

      if (res.status === 403) {
        const data = await res.json()
        setCourierStatus(data.courierStatus || 'PENDING_REVIEW')
        setCourierStatusError(data.error || 'حسابك لسه تحت المراجعة')
        setPendingOrders([])
        return
      }

      if (res.ok) {
        const data = await res.json()
        const newOrders = data.orders || []
        setCourierStatus('APPROVED')
        setCourierStatusError(null)

        // Check for genuinely new orders (not in current list)
        setPendingOrders(prev => {
          const prevIds = new Set(prev.map((o: Order) => o.id))
          const hasNew = newOrders.some((o: Order) => !prevIds.has(o.id))
          if (hasNew && prev.length > 0) {
            toast('🆕 طلب جديد وصل!', { icon: '📦', duration: 3000 })
          }
          return newOrders
        })
        setLastRefresh(new Date())
      }
    } catch { /* silent — no toast on background refresh */ }
  }, [token, isOnline])

  const fetchMyOrders = useCallback(async () => {
    if (!token) return
    try {
      const res = await fetch(`${API}/orders/my`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      if (res.ok) {
        const data = await res.json()
        setMyOrders(data.orders || [])
      }
    } catch { /* silent */ }
  }, [token])

  // Initial load
  useEffect(() => {
    async function init() {
      setLoading(true)
      await Promise.all([fetchPendingOrders(), fetchMyOrders()])
      setLoading(false)
    }
    init()
  }, [])

  // Auto-refresh pending orders
  useEffect(() => {
    if (!isOnline) return
    const interval = setInterval(() => {
      fetchPendingOrders()
    }, REFRESH_INTERVAL_MS)
    return () => clearInterval(interval)
  }, [isOnline, fetchPendingOrders])

  async function acceptOrder(orderId: string) {
    if (!token) return
    setAccepting(orderId)
    try {
      const res = await fetch(`${API}/orders/${orderId}/accept`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
      })
      const data = await res.json()

      if (res.ok && data.success) {
        toast.success('✅ تم قبول الطلب! اتحرك بسرعة 🛵')
        setPendingOrders(prev => prev.filter(o => o.id !== orderId))
        await fetchMyOrders()
        setTab('mine')
      } else if (res.status === 409) {
        toast.error('⚡ الأوردر اتحجز من مندوب تاني!')
        setPendingOrders(prev => prev.filter(o => o.id !== orderId))
      } else {
        toast.error(data.error || 'مقدرناش تقبل الأوردر')
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    } finally {
      setAccepting(null)
    }
  }

  async function updateOrderStatus(orderId: string, status: 'PICKED_UP' | 'DELIVERED') {
    if (!token) return
    setUpdatingStatus(orderId)
    try {
      const res = await fetch(`${API}/orders/${orderId}/status`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ status }),
      })
      if (res.ok) {
        const labels: Record<string, string> = {
          PICKED_UP: '📦 تم الاستلام من المحل',
          DELIVERED: '✅ تم التوصيل بنجاح!'
        }
        toast.success(labels[status] || 'تم التحديث')
        setMyOrders(prev => prev.map(o => o.id === orderId ? { ...o, status } : o))
      } else {
        toast.error('مقدرناش نحدث الحالة')
      }
    } catch {
      toast.error('مشكلة في الاتصال')
    } finally {
      setUpdatingStatus(null)
    }
  }

  const timeSince = (date: string) => {
    const mins = Math.floor((Date.now() - new Date(date).getTime()) / 60000)
    if (mins < 1) return 'الآن'
    if (mins < 60) return `${mins} دقيقة`
    return `${Math.floor(mins / 60)} ساعة`
  }

  const todayEarnings = myOrders
    .filter(o => o.status === 'DELIVERED')
    .reduce((sum, o) => sum + o.delivery_fee, 0)

  const activeOrders = myOrders.filter(o => ['ACCEPTED', 'PICKED_UP'].includes(o.status))

  // ===== Not approved yet =====
  if (courierStatus && courierStatus !== 'APPROVED') {
    return (
      <div className="max-w-md mx-auto py-12 text-center space-y-4">
        <div className="w-20 h-20 bg-yellow-100 rounded-full flex items-center justify-center mx-auto">
          <Clock className="text-yellow-500" size={40} />
        </div>
        <h2 className="text-xl font-black">
          {courierStatus === 'PENDING_REVIEW' ? 'حسابك تحت المراجعة ⏳' :
           courierStatus === 'REJECTED' ? 'تم رفض حسابك ❌' :
           courierStatus === 'SUSPENDED' ? 'حسابك موقوف ⛔' :
           'حالة غير معروفة'}
        </h2>
        <p className="text-gray-500">{courierStatusError || 'لم يتم الموافقة على حسابك بعد'}</p>
        {courierStatus === 'PENDING_REVIEW' && (
          <div className="card text-right space-y-2 text-sm text-gray-600">
            <p>✅ تم استلام بياناتك</p>
            <p>⏳ الأدمن بيراجع صور البطاقة</p>
            <p>📱 هيبلغوك بالنتيجة خلال 24 ساعة</p>
          </div>
        )}
        {courierStatus === 'NOT_REGISTERED' && (
          <button onClick={() => navigate('/courier/register')} className="btn-primary">
            أكمّل التسجيل
          </button>
        )}
        <button
          onClick={async () => {
            setLoading(true)
            await fetchPendingOrders()
            setLoading(false)
          }}
          className="btn-secondary flex items-center justify-center gap-2 mx-auto">
          <RefreshCw size={16} /> تحقق من الحالة
        </button>
      </div>
    )
  }

  return (
    <div className="space-y-5 max-w-2xl mx-auto">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-black">أهلاً {user.name?.split(' ')[0]} 👋</h1>
          <p className="text-gray-500 text-sm">
            آخر تحديث: {lastRefresh.toLocaleTimeString('ar-EG')}
          </p>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => { fetchPendingOrders(); fetchMyOrders() }}
            className="p-2 hover:bg-gray-100 rounded-xl transition-colors" title="تحديث">
            <RefreshCw size={18} className="text-gray-500" />
          </button>
          <button
            onClick={() => {
              setIsOnline(!isOnline)
              toast.success(!isOnline ? '🟢 متاح للطلبات' : '🔴 تم إيقاف الاستقبال')
            }}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl font-bold text-sm transition-all ${
              isOnline ? 'bg-green-100 text-green-700 hover:bg-green-200' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
            }`}
          >
            {isOnline ? <Wifi size={16} /> : <WifiOff size={16} />}
            {isOnline ? 'متاح' : 'غير متاح'}
          </button>
        </div>
      </div>

      {/* Live Indicator */}
      <div className={`flex items-center gap-3 rounded-xl px-4 py-3 ${
        isOnline ? 'bg-green-50 border border-green-200' : 'bg-gray-100 border border-gray-200'
      }`}>
        <span className={`w-2.5 h-2.5 rounded-full block flex-shrink-0 ${
          isOnline ? 'bg-green-500 animate-pulse' : 'bg-gray-400'
        }`} />
        <span className={`font-bold text-sm ${isOnline ? 'text-green-700' : 'text-gray-500'}`}>
          {isOnline ? 'متصل — الطلبات بتظهر تلقائياً كل 15 ثانية ⚡' : 'غير متصل — لن تستقبل طلبات'}
        </span>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-3 gap-3">
        <div className="card text-center py-3">
          <div className="text-2xl font-black text-orange-500">{pendingOrders.length}</div>
          <div className="text-xs text-gray-500">طلبات جديدة</div>
        </div>
        <div className="card text-center py-3">
          <div className="text-2xl font-black text-blue-500">{activeOrders.length}</div>
          <div className="text-xs text-gray-500">جاري التوصيل</div>
        </div>
        <div className="card text-center py-3">
          <div className="text-2xl font-black text-green-500">{todayEarnings}</div>
          <div className="text-xs text-gray-500">جنيه اليوم</div>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-1 bg-gray-100 p-1 rounded-xl">
        <button onClick={() => setTab('pending')}
          className={`flex-1 py-2.5 rounded-lg font-bold text-sm transition-all ${tab === 'pending' ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-600'}`}>
          طلبات جديدة ({pendingOrders.length})
        </button>
        <button onClick={() => setTab('mine')}
          className={`flex-1 py-2.5 rounded-lg font-bold text-sm transition-all ${tab === 'mine' ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-600'}`}>
          طلباتي ({myOrders.length})
        </button>
      </div>

      {/* Pending Orders */}
      {tab === 'pending' && (
        <div className="space-y-3">
          {!isOnline ? (
            <div className="text-center py-12">
              <WifiOff size={48} className="mx-auto mb-3 text-gray-300" />
              <p className="text-gray-500">فعّل "متاح" عشان تشوف الطلبات</p>
            </div>
          ) : loading ? (
            Array.from({ length: 3 }).map((_, i) => (
              <div key={i} className="card animate-pulse h-32 bg-gray-100" />
            ))
          ) : pendingOrders.length === 0 ? (
            <div className="text-center py-12">
              <Package size={48} className="mx-auto mb-3 text-gray-300" />
              <p className="text-gray-500 font-semibold">مفيش طلبات جديدة دلوقتي</p>
              <p className="text-gray-400 text-sm">لما يجي طلب هيظهر هنا تلقائياً</p>
            </div>
          ) : (
            pendingOrders.map(order => (
              <div key={order.id} className="card border-r-4 border-orange-500">
                <div className="flex items-start justify-between mb-3">
                  <div className="flex items-center gap-2">
                    <div className="w-10 h-10 bg-orange-100 rounded-xl flex items-center justify-center flex-shrink-0">
                      {order.type === 'SHOPPING'
                        ? <ShoppingBag className="text-orange-500" size={20} />
                        : <Truck className="text-orange-500" size={20} />
                      }
                    </div>
                    <div>
                      <div className="font-bold text-sm">{order.order_number}</div>
                      <div className="flex items-center gap-2 text-xs text-gray-400">
                        <Clock size={11} />
                        منذ {timeSince(order.created_at)}
                      </div>
                    </div>
                  </div>
                  <div className="text-left">
                    <div className="text-orange-600 font-black text-xl">{order.delivery_fee} ج</div>
                    {order.type === 'DELIVERY' && order.distance_km && order.distance_km > 0 && (
                      <div className="text-xs text-gray-400">{order.distance_km} كم</div>
                    )}
                    {order.type === 'SHOPPING' && order.num_shops && order.num_shops > 0 && (
                      <div className="text-xs text-gray-400">{order.num_shops} محل</div>
                    )}
                  </div>
                </div>

                {/* Order Items */}
                {order.order_items && order.order_items.length > 0 && (
                  <div className="mb-3 bg-gray-50 rounded-xl p-3">
                    <div className="text-xs text-gray-500 mb-1 font-semibold">المنتجات:</div>
                    {order.order_items.slice(0, 5).map((item, i) => (
                      <div key={i} className="text-sm text-gray-700">
                        • {item.name} × {item.quantity}
                        {item.shop_name && <span className="text-orange-500 text-xs"> [{item.shop_name}]</span>}
                      </div>
                    ))}
                    {order.order_items.length > 5 && (
                      <div className="text-xs text-gray-400 mt-1">+{order.order_items.length - 5} منتجات أكتر</div>
                    )}
                  </div>
                )}

                {/* Route */}
                <div className="flex items-start gap-1 text-gray-500 text-sm mb-1">
                  <MapPin size={14} className="mt-0.5 flex-shrink-0 text-green-500" />
                  <span>{order.pickup_details}</span>
                </div>
                {order.delivery_details && (
                  <div className="flex items-start gap-1 text-gray-500 text-sm mb-3">
                    <MapPin size={14} className="mt-0.5 flex-shrink-0 text-red-500" />
                    <span>{order.delivery_details}</span>
                  </div>
                )}

                {order.recipient_phone && (
                  <div className="flex items-center gap-1 text-xs text-blue-600 mb-3">
                    <Phone size={12} />
                    <span dir="ltr">{order.recipient_phone}</span>
                  </div>
                )}

                {order.notes && (
                  <div className="text-xs text-gray-400 bg-gray-50 rounded-lg p-2 mb-3">
                    💬 {order.notes}
                  </div>
                )}

                <button
                  disabled={accepting === order.id}
                  onClick={() => acceptOrder(order.id)}
                  className="w-full bg-orange-500 hover:bg-orange-600 active:scale-95 text-white font-black py-3 rounded-xl transition-all flex items-center justify-center gap-2 disabled:opacity-50 text-lg shadow-lg"
                >
                  {accepting === order.id ? (
                    <><div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent" />جاري القبول...</>
                  ) : (
                    <><CheckCircle size={22} />قبول الطلب ⚡</>
                  )}
                </button>
              </div>
            ))
          )}
        </div>
      )}

      {/* My Orders */}
      {tab === 'mine' && (
        <div className="space-y-3">
          {myOrders.length === 0 ? (
            <div className="text-center py-12">
              <Truck size={48} className="mx-auto mb-3 text-gray-300" />
              <p className="text-gray-500">مش عندك طلبات لحد دلوقتي</p>
              <button onClick={() => setTab('pending')} className="btn-primary mt-4 text-sm py-2 px-4">
                شوف الطلبات الجديدة
              </button>
            </div>
          ) : (
            myOrders.map(order => (
              <div key={order.id} className="card">
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                    {order.type === 'SHOPPING'
                      ? <ShoppingBag size={18} className="text-orange-500" />
                      : <Truck size={18} className="text-blue-500" />
                    }
                    <div className="font-bold text-sm">{order.order_number}</div>
                  </div>
                  <span className={`text-xs font-bold px-2 py-1 rounded-full ${
                    order.status === 'DELIVERED' ? 'bg-green-100 text-green-700' :
                    order.status === 'ACCEPTED' ? 'bg-blue-100 text-blue-700' :
                    order.status === 'PICKED_UP' ? 'bg-purple-100 text-purple-700' :
                    'bg-yellow-100 text-yellow-700'
                  }`}>
                    {order.status === 'DELIVERED' ? '✅ تم التوصيل' :
                     order.status === 'ACCEPTED' ? '🛵 تم القبول' :
                     order.status === 'PICKED_UP' ? '📦 مع المندوب' : order.status}
                  </span>
                </div>

                <div className="text-orange-600 font-bold mb-2">{order.delivery_fee} جنيه</div>

                {order.pickup_details && (
                  <div className="text-xs text-gray-500 mb-1">
                    <MapPin size={11} className="inline ml-1 text-green-500" />
                    {order.pickup_details}
                  </div>
                )}
                {order.delivery_details && (
                  <div className="text-xs text-gray-500 mb-3">
                    <MapPin size={11} className="inline ml-1 text-red-500" />
                    {order.delivery_details}
                  </div>
                )}

                {order.recipient_phone && (
                  <a href={`tel:${order.recipient_phone}`}
                    className="flex items-center gap-1 text-xs text-blue-600 mb-3 hover:underline">
                    <Phone size={12} />
                    <span dir="ltr">{order.recipient_phone}</span>
                  </a>
                )}

                {order.status === 'ACCEPTED' && (
                  <button
                    disabled={updatingStatus === order.id}
                    onClick={() => updateOrderStatus(order.id, 'PICKED_UP')}
                    className="w-full bg-blue-500 hover:bg-blue-600 text-white font-bold py-2.5 rounded-xl text-sm flex items-center justify-center gap-2 disabled:opacity-50">
                    {updatingStatus === order.id ? (
                      <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent" />
                    ) : null}
                    📦 تأكيد الاستلام من المحل/المرسل
                  </button>
                )}
                {order.status === 'PICKED_UP' && (
                  <button
                    disabled={updatingStatus === order.id}
                    onClick={() => updateOrderStatus(order.id, 'DELIVERED')}
                    className="w-full bg-green-500 hover:bg-green-600 text-white font-bold py-2.5 rounded-xl text-sm flex items-center justify-center gap-2 disabled:opacity-50">
                    {updatingStatus === order.id ? (
                      <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent" />
                    ) : null}
                    ✅ تأكيد التوصيل للمستلم
                  </button>
                )}
              </div>
            ))
          )}
        </div>
      )}
    </div>
  )
}

// =============================================================
// App Router - مع Admin Guard على /admin-secret
// =============================================================

import { useEffect } from 'react'
import {
  Routes, Route, Navigate,
  useNavigate, useLocation,
  Outlet, Link, useLocation as useLoc
} from 'react-router-dom'
import {
  ShieldCheck, Package, Users, Truck, TrendingUp, Megaphone, Home as HomeIcon
} from 'lucide-react'

import Layout from './components/Layout'
import HomePage from './pages/HomePage'
import OrderPage from './pages/OrderPage'
import MyOrders from './pages/MyOrders'
import TrackOrder from './pages/TrackOrder'
import Notifications from './pages/Notifications'
import LoginPage from './pages/auth/Login'
import OnboardingPage from './pages/Onboarding'
import ClientProfile from './pages/ClientProfile'
import CourierDashboard from './pages/courier/Dashboard'
import CourierProfile from './pages/courier/Profile'
import CourierRegister from './pages/courier/Register'
import CourierEarnings from './pages/courier/Earnings'
import AdminDashboard from './pages/admin/Dashboard'
import AdminPricing from './pages/admin/Pricing'
import AdminAds from './pages/admin/Ads'
import AdminCouriers from './pages/admin/Couriers'
import AdminClients from './pages/admin/Clients'
import AdminOrders from './pages/admin/Orders'
import { useAuth } from './lib/auth-context'

// =============================================================
// Guard: Onboarding
// =============================================================
function OnboardingGuard({ children }: { children: React.ReactNode }) {
  const { isLoggedIn, isLoading, needsOnboarding } = useAuth()
  const navigate = useNavigate()
  const location = useLocation()

  useEffect(() => {
    if (!isLoading && isLoggedIn && needsOnboarding && location.pathname !== '/onboarding') {
      navigate('/onboarding', { replace: true })
    }
  }, [isLoading, isLoggedIn, needsOnboarding, location.pathname, navigate])

  return <>{children}</>
}

// =============================================================
// Guard: Admin only
// =============================================================
function AdminGuard({ children }: { children: React.ReactNode }) {
  const { user, isLoggedIn } = useAuth()
  if (!isLoggedIn) return <Navigate to="/login" replace />
  if (user?.role !== 'admin') return <Navigate to="/" replace />
  return <>{children}</>
}

// =============================================================
// Admin Layout
// =============================================================
function AdminLayout() {
  const location = useLoc()

  const links = [
    { to: '/admin-secret', label: 'الرئيسية', icon: <HomeIcon size={18} />, exact: true },
    { to: '/admin-secret/orders', label: 'الأوردرات', icon: <Package size={18} /> },
    { to: '/admin-secret/couriers', label: 'المناديب', icon: <Truck size={18} /> },
    { to: '/admin-secret/clients', label: 'العملاء', icon: <Users size={18} /> },
    { to: '/admin-secret/pricing', label: 'الأسعار', icon: <TrendingUp size={18} /> },
    { to: '/admin-secret/ads', label: 'الإعلانات', icon: <Megaphone size={18} /> },
  ]

  const isActive = (to: string, exact?: boolean) =>
    exact
      ? location.pathname === to
      : location.pathname === to || location.pathname.startsWith(to + '/')

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="bg-purple-700 text-white px-4 py-3">
        <div className="max-w-4xl mx-auto flex items-center gap-3">
          <ShieldCheck size={24} />
          <span className="font-black text-lg">لوحة أدمن مندوبك</span>
        </div>
      </div>
      <div className="bg-purple-600 text-white px-4">
        <div className="max-w-4xl mx-auto flex gap-1 overflow-x-auto">
          {links.map(link => (
            <Link
              key={link.to}
              to={link.to}
              className={`flex items-center gap-1.5 px-3 py-3 text-sm font-bold whitespace-nowrap transition-all border-b-2 ${
                isActive(link.to, link.exact)
                  ? 'border-white text-white'
                  : 'border-transparent text-purple-200 hover:text-white'
              }`}
            >
              {link.icon}
              {link.label}
            </Link>
          ))}
        </div>
      </div>
      <div className="max-w-4xl mx-auto px-4 py-6">
        <Outlet />
      </div>
    </div>
  )
}

// =============================================================
// Main App
// =============================================================
export default function App() {
  return (
    <OnboardingGuard>
      <Routes>
        {/* Full-screen pages */}
        <Route path="/onboarding" element={<OnboardingPage />} />

        {/* Admin — hidden URL, guarded */}
        <Route
          path="/admin-secret"
          element={<AdminGuard><AdminLayout /></AdminGuard>}
        >
          <Route index element={<AdminDashboard />} />
          <Route path="orders" element={<AdminOrders />} />
          <Route path="couriers" element={<AdminCouriers />} />
          <Route path="clients" element={<AdminClients />} />
          <Route path="pricing" element={<AdminPricing />} />
          <Route path="ads" element={<AdminAds />} />
        </Route>

        {/* Main app layout */}
        <Route element={<Layout />}>
          <Route path="/" element={<HomePage />} />
          <Route path="/login" element={<LoginPage />} />
          <Route path="/notifications" element={<Notifications />} />

          <Route path="/order" element={<OrderPage />} />
          <Route path="/my-orders" element={<MyOrders />} />
          <Route path="/track/:id" element={<TrackOrder />} />
          <Route path="/profile" element={<ClientProfile />} />

          <Route path="/courier/register" element={<CourierRegister />} />
          <Route path="/courier/dashboard" element={<CourierDashboard />} />
          <Route path="/courier/profile" element={<CourierProfile />} />
          <Route path="/courier/earnings" element={<CourierEarnings />} />

          {/* Old admin paths → redirect away */}
          <Route path="/admin" element={<Navigate to="/" replace />} />
          <Route path="/admin/*" element={<Navigate to="/" replace />} />
        </Route>

        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </OnboardingGuard>
  )
}

